class Solution:
    def friendRequests(self, n: int, restrictions: List[List[int]], requests: List[List[int]]) -> List[bool]:
        parent = list(range(n))
        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]
        def union(x, y):
            rootx, rooty = find(x), find(y)
            if rootx != rooty:
                parent[rootx] = rooty
        for x, y in restrictions:
            if find(x) == find(y):
                return [False] * len(requests)
        res = []
        for x, y in requests:
            if find(x) != find(y):
                union(x, y)
                res.append(True)
            else:
                res.append(True)
        return res
